// HTTP-triggered function for on-demand batch processing
app.http('batchProcessorHttp', {
    methods: ['POST'],
    authLevel: 'function',
    handler: async (request, context) => {
        context.log('HTTP-triggered batch processor invoked.');

        let jobId;
        let action;

        try {
            const body = await request.json();
            jobId = body.jobId || `job_${Date.now()}`;
            action = body.action || 'process';
        } catch {
            jobId = `job_${Date.now()}`;
            action = 'process';
        }

        const processor = new BatchProcessor(context);

        if (action === 'status') {
            // Return current job status
            try {
                const checkpoint = await processor.loadCheckpoint(jobId);
                return {
                    status: 200,
                    jsonBody: {
                        jobId,
                        checkpoint
                    }
                };
            } catch (error) {
                return {
                    status: 500,
                    jsonBody: { error: error.message }
                };
            }
        }

        if (action === 'reset') {
            // Reset checkpoint to start fresh
            try {
                const checkpoint = {
                    id: jobId,
                    partitionKey: jobId,
                    continuationToken: null,
                    processedCount: 0,
                    errorCount: 0,
                    status: 'reset',
                    createdAt: new Date().toISOString(),
                    lastUpdatedAt: new Date().toISOString()
                };
                await processor.saveCheckpoint(checkpoint);
                return {
                    status: 200,
                    jsonBody: { message: 'Checkpoint reset', jobId }
                };
            } catch (error) {
                return {
                    status: 500,
                    jsonBody: { error: error.message }
                };
            }
        }

        // Process action
        try {
            const result = await processor.processBatches(jobId);
            return {
                status: 200,
                jsonBody: {
                    jobId,
                    ...result,
                    message: result.status === 'paused'
                        ? 'Processing paused due to approaching timeout. Invoke again to resume.'
                        : 'Processing completed successfully.'
                }
            };
        } catch (error) {
            context.error(`Batch processing failed: ${error.message}`);
            return {
                status: 500,
                jsonBody: {
                    jobId,
                    error: error.message,
                    processedCount: processor.processedCount,
                    errorCount: processor.errorCount
                }
            };
        }
    }
});

